const ESCUDO_LG='data:image/png;base64,';
const ESCUDO_MD='data:image/png;base64,';
const FOTO_CEO_LG='data:image/png;base64,';
const FOTO_CEO_SM='data:image/png;base64,';
function getCeoPhoto(size){const k='asm_ceo_photo_'+size;const v=localStorage.getItem(k);return v||((size==='lg')?FOTO_CEO_LG:FOTO_CEO_SM)}
function setCeoPhoto(dataUrl){localStorage.setItem('asm_ceo_photo_lg',dataUrl);localStorage.setItem('asm_ceo_photo_sm',dataUrl)}
function openPhotoModal(){openModal('Alterar Foto de Perfil','<div class="field"><label>Selecionar nova foto</label><div class="field-file"><input type="file" id="mPhoto" accept="image/*" onchange="previewPhoto(this)"><div class="file-label">'+I.file+' <span id="mPhotoL">Clique para selecionar imagem</span></div></div></div><div id="photoPreview" style="text-align:center;margin-top:12px"></div>','<button class="btn-ghost" onclick="closeModal()">Cancelar</button><button class="btn-primary" onclick="savePhoto()">Salvar</button>')}
let pendingPhoto=null;
function previewPhoto(inp){const f=inp.files[0];if(!f)return;pendingPhoto=f;document.getElementById('mPhotoL').textContent=f.name;const r=new FileReader();r.onload=function(e){document.getElementById('photoPreview').innerHTML='<img src="'+e.target.result+'" style="width:80px;height:80px;border-radius:12px;object-fit:cover;border:2px solid var(--vm)">'};r.readAsDataURL(f)}
function savePhoto(){if(!pendingPhoto){showToast('Selecione uma foto','dg');return}const r=new FileReader();r.onload=function(e){setCeoPhoto(e.target.result);pendingPhoto=null;closeModal();updateAvatars();showToast('Foto atualizada!','ok')};r.readAsDataURL(pendingPhoto)}
function updateAvatars(){const photo=getCeoPhoto('lg');document.querySelectorAll('.ceo-avatar-img').forEach(function(el){el.src=photo})}

/* ═══ DB ═══ */
function saveData(k,d){try{localStorage.setItem('asm_'+k,JSON.stringify(d))}catch(e){}}
function loadData(k,fb){try{const d=localStorage.getItem('asm_'+k);return d?JSON.parse(d):fb}catch(e){return fb}}
const uid=()=>Date.now().toString(36)+Math.random().toString(36).substr(2,5);
function getUsers(){return loadData('users',{CEO:{pass:'251233Deus',label:'CEO',avatar:'CV',name:'Dr. Claudio Vitti',role:'CEO · Presidente'},Administrador:{pass:'251233Deus',label:'Administrador',avatar:'AD',name:'Administrador',role:'Acesso Total'}})}
function saveUsers(u){saveData('users',u)}

/* ═══ AUTH ═══ */
let currentUser=null;
function attemptLogin(){const role=document.getElementById('loginRole').value,pass=document.getElementById('loginPass').value,err=document.getElementById('loginError'),users=getUsers(),u=users[role];
  if(u&&pass===u.pass){err.classList.remove('show');currentUser={key:role,label:u.label,avatar:u.avatar,name:u.name,role:u.role,isAdmin:role==='Administrador'};sessionStorage.setItem('asm_session',JSON.stringify(currentUser));document.getElementById('loginScreen').classList.add('hidden');setTimeout(()=>{document.getElementById('loginScreen').style.display='none';document.getElementById('appMain').classList.add('visible');applyPerm();updateUI();buildNav();renderPage()},500)}
  else{err.classList.add('show');document.getElementById('loginPass').value='';document.getElementById('loginPass').focus()}}
function applyPerm(){if(!currentUser)return;document.body.className=currentUser.isAdmin?'role-admin':'role-ceo'}
function canEdit(){return currentUser&&currentUser.isAdmin}
function openChangePwLogin(){const r=document.getElementById('loginRole').value,c=prompt('Senha atual:'),u=getUsers();if(!u[r]||c!==u[r].pass){alert('Incorreta.');return}const n=prompt('Nova senha (min 4):');if(!n||n.length<4){alert('Mínimo 4 caracteres.');return}u[r].pass=n;saveUsers(u);alert('Senha alterada!')}
function openChangePwModal(){if(!currentUser)return;openModal('Alterar Senha','<div class="field"><label>Senha Atual</label><input type="password" id="mCP"></div><div class="field"><label>Nova Senha</label><input type="password" id="mNP"></div><div class="field"><label>Confirmar</label><input type="password" id="mCF"></div>','<button class="btn-ghost" onclick="closeModal()">Cancelar</button><button class="btn-primary" onclick="doChangePw()">Salvar</button>')}
function doChangePw(){const c=document.getElementById('mCP').value,n=document.getElementById('mNP').value,f=document.getElementById('mCF').value,u=getUsers();if(c!==u[currentUser.key].pass){showToast('Senha incorreta','dg');return}if(n.length<4){showToast('Mínimo 4','dg');return}if(n!==f){showToast('Não conferem','dg');return}u[currentUser.key].pass=n;saveUsers(u);closeModal();showToast('Senha alterada!','ok')}
function updateUI(){if(!currentUser)return;['sidebarName','headerName'].forEach(id=>{const e=document.getElementById(id);if(e)e.textContent=currentUser.name});document.getElementById('sidebarRole').textContent=currentUser.label;document.getElementById('headerRoleText').textContent=currentUser.label;document.getElementById('headerRole').textContent=currentUser.isAdmin?'ADMIN':'CEO';const photo=getCeoPhoto('lg');document.querySelectorAll('.ceo-avatar-img').forEach(function(el){el.src=photo})}
function logout(){sessionStorage.removeItem('asm_session');location.reload()}
(function(){const s=sessionStorage.getItem('asm_session');if(s){currentUser=JSON.parse(s);document.getElementById('loginScreen').style.display='none';document.getElementById('appMain').classList.add('visible');applyPerm();updateUI()}})();
document.getElementById('loginPass').addEventListener('keydown',e=>{if(e.key==='Enter')attemptLogin()});

