let pendOpPdf=null;
function openOpM(eid){const ops=gOp(),o=eid?ops.find(x=>x.id===eid):null;pendOpPdf=null;openModal(o?'Editar':'Novo Edital',`<div class="field"><label>Nome</label><input id="mON" value="${o?o.nome:''}"></div><div class="field-row"><div class="field"><label>Órgão</label><input id="mOO" value="${o?o.orgao:''}"></div><div class="field"><label>UF</label><input id="mOE" value="${o?o.estado:''}" maxlength="2"></div></div><div class="field"><label>Objeto</label><textarea id="mOOb" rows="2">${o?o.objeto||'':''}</textarea></div><div class="field-row"><div class="field"><label>Valor</label><input id="mOV" value="${o?o.valor:''}"></div><div class="field"><label>Data</label><input id="mOD" value="${o?o.data:''}"></div></div><div class="field"><label>Status</label><select id="mOS"><option value="Prospecção">Prospecção</option><option value="Em análise" ${!o||o.status==='Em análise'?'selected':''}>Em análise</option><option value="Qualificação" ${o&&o.status==='Qualificação'?'selected':''}>Qualificação</option><option value="Negociação" ${o&&o.status==='Negociação'?'selected':''}>Negociação</option><option value="Aprovado" ${o&&o.status==='Aprovado'?'selected':''}>Aprovado</option></select></div><div class="field"><label>PDF Edital</label><div class="field-file"><input type="file" accept=".pdf" onchange="pendOpPdf=this.files[0];document.getElementById('mOPL').textContent=this.files[0]?.name||'Selecionar'"><div class="file-label">${I.file} <span id="mOPL">${o&&o.pdfName?o.pdfName:'Selecionar PDF'}</span></div></div></div>`,`${o?`<button class="btn-sm btn-danger" onclick="deleteItem('oportunidades','${o.id}')">Excluir</button>`:''}<button class="btn-ghost" onclick="closeModal()">Cancelar</button><button class="btn-primary" onclick="saveOp('${eid||''}')">Salvar</button>`)}
function saveOp(eid){const ops=gOp(),o={id:eid||uid(),nome:document.getElementById('mON').value,orgao:document.getElementById('mOO').value,estado:document.getElementById('mOE').value.toUpperCase(),objeto:document.getElementById('mOOb').value,valor:document.getElementById('mOV').value,data:document.getElementById('mOD').value,status:document.getElementById('mOS').value,pdf:'',pdfName:''};if(!o.nome){showToast('Preencha','dg');return}if(eid){const old=ops.find(x=>x.id===eid);if(old&&old.pdf){o.pdf=old.pdf;o.pdfName=old.pdfName}}if(pendOpPdf){const r=new FileReader();r.onload=e=>{o.pdf=e.target.result;o.pdfName=pendOpPdf.name;pendOpPdf=null;_saveOp(ops,o,eid)};r.readAsDataURL(pendOpPdf);return}pendOpPdf=null;_saveOp(ops,o,eid)}
function _saveOp(ops,o,eid){if(eid){const i=ops.findIndex(x=>x.id===eid);if(i>=0)ops[i]=o}else ops.unshift(o);saveData('oportunidades',ops);closeModal();renderPage();showToast('Salvo!','ok')}

