function savePj(eid){const p=gPj(),o={id:eid||uid(),name:document.getElementById('mPN').value,resp:document.getElementById('mPR').value,prazo:document.getElementById('mPP').value,prog:+document.getElementById('mPPr').value||0,status:document.getElementById('mPS').value};if(!o.name){showToast('Preencha','dg');return}if(eid){const i=p.findIndex(x=>x.id===eid);if(i>=0)p[i]=o}else p.unshift(o);saveData('projects',p);closeModal();renderPage();showToast('Salvo!','ok')}

