/* ═══ SOFIA IA — INTELIGÊNCIA AVANÇADA COM CLAUDE API ═══ */
let sofiaOpen=false;
let sofiaHistory=[]; // Histórico para conversa contínua
function toggleSofia(){sofiaOpen=!sofiaOpen;document.getElementById('sofiaPanel').classList.toggle('show',sofiaOpen);document.getElementById('sofiaBtn').style.display=sofiaOpen?'none':'flex';if(sofiaOpen)document.getElementById('sofiaInput').focus()}
function addSMsg(t,tp){const c=document.getElementById('sofiaMessages'),d=document.createElement('div');d.className='sofia-msg '+tp;d.innerHTML=t;c.appendChild(d);c.scrollTop=c.scrollHeight;return d}

function getSofiaSystem(){
  const ag=gAg(),tk=gTk(),pj=gPj(),ops=gOp(),ql=gQl(),fin=getFin(),lg=gLg(),st=gSt();
  let rT=0,dT=0;for(let i=0;i<12;i++){rT+=+(fin.meses[i]?.receita||0);dT+=+(fin.meses[i]?.despesa||0)}
  const unInfo=UNI.map(u=>`• ${u.m}/${u.e}: ${u.r}. Serviços: ${u.n.map(n=>n.l+': '+n.i.join(', ')).join('; ')}`).join('\n');
  return `Você é SOFIA (Sistema Operacional Facilitador de Inteligência Assistencial), a assistente de IA executiva da ASM — Associação Saúde em Movimento. Você foi projetada para atender o CEO e a diretoria executiva com informações estratégicas, análises e respostas inteligentes.

IDENTIDADE:
- Nome: SOFIA
- Função: Assistente IA executiva da ASM
- Estilo: Profissional, objetivo, estratégico, mas acessível
- Idioma: Português brasileiro

CAPACIDADES:
1. Responder perguntas sobre TODOS os dados internos da ASM (abaixo)
2. Responder perguntas gerais sobre saúde pública, gestão hospitalar, SUS, legislação sanitária, licitações, compliance
3. Fazer análises estratégicas e dar recomendações executivas
4. Explicar conceitos de gestão, finanças, qualidade assistencial
5. Ajudar com redação de documentos, pareceres, notas técnicas
6. Discutir tendências do setor de saúde e gestão de OS

DADOS ATUAIS DA ASM (use para responder sobre dados internos):

FINANCEIRO:
- Receita acumulada 2026: R$ ${rT.toLocaleString('pt-BR',{minimumFractionDigits:2})}
- Despesa acumulada: R$ ${dT.toLocaleString('pt-BR',{minimumFractionDigits:2})}
- Resultado líquido: R$ ${(rT-dT).toLocaleString('pt-BR',{minimumFractionDigits:2})}
- Margem: ${rT>0?((rT-dT)/rT*100).toFixed(1):'0'}%

AGENDA DE HOJE (${new Date().toLocaleDateString('pt-BR')}):
${ag.map(a=>'- '+a.time+' '+a.title+' ('+a.local+', '+a.status+')').join('\n')}

TAREFAS:
- Total: ${tk.length} | Pendentes: ${tk.filter(t=>t.st!=='concluída').length} | Urgentes: ${tk.filter(t=>t.pri==='urgente').length}
${tk.map(t=>'- ['+t.st.toUpperCase()+'] '+t.task+' ('+t.who+', prazo: '+t.due+', prioridade: '+t.pri+')').join('\n')}

PROJETOS:
${pj.map(p=>'- '+p.name+': '+p.prog+'% ('+p.status+') — Resp: '+(p.resp||'—')+', Prazo: '+p.prazo).join('\n')}

OPORTUNIDADES COMERCIAIS:
${ops.map(o=>'- '+o.nome+' | '+o.orgao+'/'+o.estado+' | '+o.valor+' | Status: '+o.status).join('\n')}

INDICADORES ASSISTENCIAIS:
${ql.map(q=>'- '+q.name+': '+q.val+q.unit+' (meta: '+q.tgt+q.unit+', tendência: '+q.trend+') — '+q.obs).join('\n')}

JURÍDICO:
${lg.map(j=>'- ['+j.cat+'] '+j.title+(j.value?' | '+j.value:'')+(j.venc?' | Venc: '+j.venc:'')+(j.status?' | '+j.status:'')).join('\n')}

GESTÃO ESTRATÉGICA:
Objetivos: ${st.objetivos.map(o=>o.titulo+' ('+o.prog+'%)').join('; ')}
Riscos: ${st.riscos.map(r=>r.titulo+' ('+r.severidade+')').join('; ')}
Decisões pendentes: ${st.decisoes.map(d=>d.titulo+' — '+d.status).join('; ')}

REDE ASSISTENCIAL (12 municípios, 5 estados, 120+ unidades):
${unInfo}

REGRAS:
- Sempre responda em português brasileiro
- Seja concisa mas completa
- Use dados internos quando disponíveis
- Para perguntas fora do escopo ASM, responda com seu conhecimento geral
- Formate respostas de forma clara e organizada
- Se não souber algo específico dos dados, diga claramente
- Pode fazer recomendações estratégicas quando solicitado`;
}

async function sendSofia(){
  const input=document.getElementById('sofiaInput'),q=input.value.trim();
  if(!q)return;input.value='';addSMsg(q,'user');
  sofiaHistory.push({role:'user',content:q});
  if(sofiaHistory.length>20)sofiaHistory=sofiaHistory.slice(-16); // Manter últimas 8 trocas
  const loadingEl=addSMsg('⏳ Analisando...','bot loading');

  try{
    const resp=await fetch('https://api.anthropic.com/v1/messages',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({
        model:'claude-sonnet-4-20250514',
        max_tokens:2000,
        system:getSofiaSystem(),
        messages:sofiaHistory,
        tools:[{type:'web_search_20250305',name:'web_search'}]
      })
    });
    const data=await resp.json();
    const text=data.content?.filter(b=>b.type==='text').map(b=>b.text||'').join('\n')||'Desculpe, não consegui processar. Tente novamente.';
    sofiaHistory.push({role:'assistant',content:text});
    loadingEl.remove();
    addSMsg(text.replace(/\n/g,'<br>'),'bot');
  }catch(e){
    loadingEl.remove();
    const fallback=localSofia(q);
    sofiaHistory.push({role:'assistant',content:fallback});
    addSMsg(fallback,'bot');
  }
}

function localSofia(q){
  const ql=q.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
  const fin=getFin(),tk=gTk(),ag=gAg(),pj=gPj(),ops=gOp(),qi=gQl();
  if(ql.includes('municipio')||ql.includes('onde atua')||ql.includes('cidades'))return`A ASM atua em <strong>12 municípios</strong> de 5 estados: ${UNI.map(u=>u.m+'/'+u.e).join(', ')}.`;
  for(const u of UNI){if(ql.includes(u.m.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,''))){return`Em <strong>${u.m}/${u.e}</strong>: ${u.r}. ${u.n.map(n=>n.l+': '+n.i.join(', ')).join('. ')}.`}}
  if(ql.includes('receita')||ql.includes('faturamento')){let r=0;for(let i=0;i<12;i++)r+=+(fin.meses[i]?.receita||0);return`Receita total: <strong>${fmtMoney(r)}</strong>.`}
  if(ql.includes('reuniao')||ql.includes('hoje')||ql.includes('agenda'))return`Hoje: <strong>${ag.length} reuniões</strong>. Próxima: "${ag[0]?.title}" às ${ag[0]?.time}.`;
  if(ql.includes('tarefa')){const p=tk.filter(t=>t.st!=='concluída');return`<strong>${p.length} tarefas pendentes</strong>. Urgentes: ${p.filter(t=>t.pri==='urgente').length}.`}
  if(ql.includes('projeto'))return`<strong>${pj.length} projetos</strong>: ${pj.map(p=>p.name+': '+p.prog+'%').join('; ')}.`;
  if(ql.includes('indicador')||ql.includes('ocupacao')||ql.includes('satisfacao'))return`Indicadores: ${qi.map(q=>q.name+': '+q.val+q.unit).join(', ')}.`;
  if(ql.includes('unidade')||ql.includes('quantas')){const t=UNI.reduce((s,u)=>s+u.n.reduce((ss,n)=>ss+n.i.length,0),0);return`Mais de <strong>${t} serviços</strong> em 12 municípios.`}
  return'Posso responder sobre municípios, unidades, receita, projetos, indicadores, oportunidades, agenda e tarefas. O que deseja saber?';
}

/* ═══ RENDER: PESSOAL — SAÚDE DO CEO ═══ */
